INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp, type) VALUES
(401, 4, 'レッスン 1', '公的保障制度の例は？', '["民間保険のみ", "健康保険・年金", "株式投資", "貯金"]', 1, '日本の公的保障には健康保険、年金、雇用保険などがあります。', 600, 60, 'quiz'),
(402, 4, 'レッスン 2', '高額療養費制度とは？', '["全額免除", "医療費上限制度", "保険なし", "自費のみ"]', 1, '医療費が一定額を超えた場合、超過分が払い戻される制度です。', 600, 60, 'quiz'),
(403, 4, 'レッスン 3', '保険加入の優先順位は？', '["貯蓄型のみ", "必要保障から", "全部同時", "不要"]', 1, '万が一のリスクに備える保障を優先すべきです。', 600, 60, 'quiz'),
(404, 4, 'レッスン 4', '貯蓄型保険のデメリットは？', '["なし", "利回りが低い", "リスクなし", "全員に最適"]', 1, '貯蓄型保険は保障と貯蓄を兼ねるため利回りが低くなりがちです。', 600, 60, 'quiz'),
(405, 4, 'レッスン 5', '掛け捨て保険のメリットは？', '["貯蓄できる", "保険料が安い", "資産形成", "投資になる"]', 1, '掛け捨て保険は保障に特化しているため保険料が安価です。', 600, 60, 'quiz'),
(406, 4, 'レッスン 6', '生命保険の主な目的は？', '["資産形成", "遺族の生活保障", "投資", "貯金"]', 1, '万が一の際に遺族の生活を守ることが主目的です。', 600, 60, 'quiz'),
(407, 4, 'レッスン 7', '医療保険の必要性は？', '["全員必須", "公的保険を補完", "不要", "高所得者のみ"]', 1, '公的保険でカバーできない部分を補完する役割があります。', 600, 60, 'quiz'),
(408, 4, 'レッスン 8', 'がん保険の特徴は？', '["全病気対象", "がんに特化", "貯蓄型のみ", "投資型"]', 1, 'がんの治療費や収入減少に特化した保険です。', 600, 60, 'quiz'),
(409, 4, 'レッスン 9', '就業不能保険とは？', '["失業時の保険", "働けない時の収入保障", "年金", "貯蓄"]', 1, '病気やケガで働けなくなった時の収入を補償します。', 600, 60, 'quiz'),
(410, 4, 'レッスン 10', '保険の見直し時期は？', '["加入時のみ", "ライフイベント時", "不要", "解約時"]', 1, '結婚、出産、住宅購入などのタイミングで見直すべきです。', 600, 60, 'quiz'),
(411, 4, 'レッスン 11', '保険料控除のメリットは？', '["なし", "税金が安くなる", "保険料が安い", "投資になる"]', 1, '生命保険料控除により所得税・住民税が軽減されます。', 600, 60, 'quiz'),
(412, 4, 'レッスン 12', '定期保険の特徴は？', '["一生涯保障", "一定期間のみ保障", "貯蓄型", "投資型"]', 1, '保険期間が決まっており、掛け捨てで保険料が安いのが特徴です。', 600, 60, 'quiz'),
(413, 4, 'レッスン 13', '終身保険の特徴は？', '["期間限定", "一生涯保障", "掛け捨てのみ", "投資型"]', 1, '一生涯保障が続き、解約返戻金がある保険です。', 600, 60, 'quiz'),
(414, 4, 'レッスン 14', '学資保険の目的は？', '["老後資金", "教育資金", "住宅資金", "投資"]', 1, '子供の教育費を計画的に準備する保険です。', 600, 60, 'quiz'),
(415, 4, 'レッスン 15', '個人年金保険の目的は？', '["教育費", "老後資金", "住宅資金", "投資"]', 1, '公的年金を補完し、老後の生活資金を準備します。', 600, 60, 'quiz'),
(416, 4, 'レッスン 16', '保険金額の決め方は？', '["最大限", "必要保障額から", "最小限", "感覚"]', 1, '遺族に必要な生活費や教育費を計算して決めます。', 600, 60, 'quiz'),
(417, 4, 'レッスン 17', '保険の見直しで注意すべきは？', '["解約すれば良い", "保障の空白期間", "無視", "全部解約"]', 1, '新しい保険が成立してから古い保険を解約すべきです。', 600, 60, 'quiz'),
(418, 4, 'レッスン 18', '保険金の受取人は？', '["自動決定", "指定が必要", "誰でも良い", "保険会社"]', 1, '保険金の受取人を明確に指定することが重要です。', 600, 60, 'quiz'),
(419, 4, 'レッスン 19', '保険証券の保管方法は？', '["不要", "安全な場所に保管", "捨てる", "デジタルのみ"]', 1, '保険証券は家族が分かる場所に大切に保管すべきです。', 600, 60, 'quiz'),
(420, 4, 'レッスン 20', '保険の相談先は？', '["誰にも相談しない", "FPや保険代理店", "知人のみ", "不要"]', 1, 'ファイナンシャルプランナーや保険代理店に相談すると良いでしょう。', 600, 60, 'quiz');
INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp, type) VALUES
(501, 5, 'レッスン 1', 'NISA の最大のメリットは？', '["課税される", "運用益が非課税", "損失補填", "必ず儲かる"]', 1, 'NISAでは株式や投資信託の運用益が非課税になります。', 700, 70, 'quiz'),
(502, 5, 'レッスン 2', 'つみたてNISAの投資対象は？', '["全商品", "金融庁認定の投信", "株式のみ", "FXのみ"]', 1, '金融庁が認定した長期・分散・積立に適した投資信託が対象です。', 700, 70, 'quiz'),
(503, 5, 'レッスン 3', 'インデックスファンドとは？', '["アクティブ運用", "市場平均に連動", "個別株", "FX"]', 1, '日経平均やS&P500など市場指数に連動する投資信託です。', 700, 70, 'quiz'),
(504, 5, 'レッスン 4', '分散投資の意義は？', '["リスク集中", "リスク分散", "リターン減少", "不要"]', 1, '複数の資産に投資することでリスクを分散できます。', 700, 70, 'quiz'),
(505, 5, 'レッスン 5', '長期投資のメリットは？', '["短期利益のみ", "複利効果", "リスクなし", "必ず儲かる"]', 1, '時間をかけることで複利効果が働き資産が増えやすくなります。', 700, 70, 'quiz'),
(506, 5, 'レッスン 6', 'ドルコスト平均法とは？', '["一括購入", "定期定額購入", "タイミング投資", "FX手法"]', 1, '毎月一定額を投資することで平均購入価格を抑える手法です。', 700, 70, 'quiz'),
(507, 5, 'レッスン 7', '投資信託の信託報酬とは？', '["初回手数料", "運用管理費用", "解約手数料", "税金"]', 1, '投資信託の運用・管理にかかる年間費用です。', 700, 70, 'quiz'),
(508, 5, 'レッスン 8', 'ETFの特徴は？', '["非上場", "上場投信", "個別株のみ", "債券のみ"]', 1, '上場している投資信託で株式のように取引できます。', 700, 70, 'quiz'),
(509, 5, 'レッスン 9', 'リバランスの目的は？', '["放置", "資産配分の調整", "全売却", "全購入"]', 1, '当初の資産配分比率に戻すことでリスクを管理します。', 700, 70, 'quiz'),
(510, 5, 'レッスン 10', '株式投資のリスクは？', '["ゼロ", "価格変動", "必ず儲かる", "元本保証"]', 1, '株価は変動するため、損失が出る可能性があります。', 700, 70, 'quiz'),
(511, 5, 'レッスン 11', '債券投資の特徴は？', '["高リスク高リターン", "低リスク低リターン", "必ず儲かる", "FX"]', 1, '株式より一般的にリスクが低く、安定した利息収入が得られます。', 700, 70, 'quiz'),
(512, 5, 'レッスン 12', '配当金とは？', '["売却益", "企業の利益分配", "手数料", "税金"]', 1, '企業が株主に利益の一部を還元するお金です。', 700, 70, 'quiz'),
(513, 5, 'レッスン 13', 'PERとは何の指標？', '["配当利回り", "株価収益率", "ROE", "PBR"]', 1, '株価が1株利益の何倍かを示す投資指標です。', 700, 70, 'quiz'),
(514, 5, 'レッスン 14', 'ROEとは？', '["売上高", "自己資本利益率", "負債比率", "配当率"]', 1, '自己資本（株主の資金）からどれだけ利益を生んだかを示します。', 700, 70, 'quiz'),
(515, 5, 'レッスン 15', '投資の基本姿勢は？', '["短期売買のみ", "長期・分散・積立", "借金で投資", "FXのみ"]', 1, '長期・分散・積立投資が資産形成の王道です。', 700, 70, 'quiz'),
(516, 5, 'レッスン 16', '投資を始める前に必要なのは？', '["借金", "生活防衛資金", "大金", "ギャンブル精神"]', 1, 'まずは生活費の3-6ヶ月分の貯蓄を確保すべきです。', 700, 70, 'quiz'),
(517, 5, 'レッスン 17', '投資詐欺の特徴は？', '["適正利回り", "高利回りを謳う", "公的機関推奨", "低リスク低リターン"]', 1, '「必ず儲かる」「高利回り確実」などは詐欺の可能性が高いです。', 700, 70, 'quiz'),
(518, 5, 'レッスン 18', '暴落時の対応は？', '["全売却", "冷静に保有継続", "借金で追加購入", "パニック"]', 1, '長期投資では一時的な下落は気にせず冷静に継続すべきです。', 700, 70, 'quiz'),
(519, 5, 'レッスン 19', '投資の目的は？', '["ギャンブル", "資産形成", "一攫千金", "浪費"]', 1, '将来の資産形成や目標達成のために計画的に行うべきです。', 700, 70, 'quiz'),
(520, 5, 'レッスン 20', '投資の勉強方法は？', '["不要", "書籍・セミナー等", "SNSのみ", "感覚"]', 1, '信頼できる書籍やセミナーで基礎知識を学ぶことが大切です。', 700, 70, 'quiz');
INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp, type) VALUES
(601, 6, 'レッスン 1', '人生の三大資金とは？', '["旅行・趣味・娯楽", "教育・住宅・老後", "車・家電・服", "全て不要"]', 1, '教育資金、住宅資金、老後資金が人生の三大資金です。', 800, 80, 'quiz'),
(602, 6, 'レッスン 2', 'iDeCoの最大のメリットは？', '["元本保証", "掛金が全額所得控除", "いつでも引出可", "必ず儲かる"]', 1, 'iDeCoの掛金は全額所得控除され、大きな節税効果があります。', 800, 80, 'quiz'),
(603, 6, 'レッスン 3', 'iDeCoの受給年齢は？', '["40歳から", "60歳から", "70歳から", "いつでも"]', 1, 'iDeCoは原則60歳から受給開始となります。', 800, 80, 'quiz'),
(604, 6, 'レッスン 4', '老後に必要な資金の目安は？', '["100万円", "2000万円前後", "1億円", "不要"]', 1, '公的年金だけでは不足するため、約2000万円の準備が推奨されます。', 800, 80, 'quiz'),
(605, 6, 'レッスン 5', '公的年金の仕組みは？', '["積立方式", "賦課方式", "投資運用", "貯金"]', 1, '現役世代が納めた保険料を高齢者に給付する賦課方式です。', 800, 80, 'quiz'),
(606, 6, 'レッスン 6', '年金の受給開始年齢は？', '["60歳", "65歳", "70歳", "75歳"]', 1, '原則65歳から受給開始ですが、繰上げ・繰下げも可能です。', 800, 80, 'quiz'),
(607, 6, 'レッスン 7', '年金の繰下げ受給のメリットは？', '["減額", "増額", "変わらない", "停止"]', 1, '受給開始を遅らせると、年金額が増額されます。', 800, 80, 'quiz'),
(608, 6, 'レッスン 8', 'ライフプラン表の作成目的は？', '["不要", "将来の収支を見える化", "現状把握のみ", "過去の分析"]', 1, '将来のライフイベントと収支を可視化することで計画的に備えられます。', 800, 80, 'quiz'),
(609, 6, 'レッスン 9', '住宅ローンの返済計画は？', '["適当で良い", "収入とバランス", "最大限借りる", "不要"]', 1, '返済額は収入の25%以内に抑えるのが理想的です。', 800, 80, 'quiz'),
(610, 6, 'レッスン 10', '教育資金の準備時期は？', '["進学直前", "早期から計画的に", "不要", "借金で対応"]', 1, '子供が小さいうちから計画的に積み立てることが重要です。', 800, 80, 'quiz'),
(611, 6, 'レッスン 11', 'Ch.6 Q11', 'テスト問題11', '["選択肢A", "選択肢B", "選択肢C", "選択肢D"]', 1, 'Chapter 6の学習内容です。', 800, 80, 'quiz'),
